    player: Entity
    monsters: list[Entity]
    log: list[str]

    def entity_at(self, point: Point) -> Entity | None:
        for monster in self.monsters:
            if monster.pos == point and monster.fighter is not None and monster.fighter.alive:
                return monster
        return None

    def move_player(self, dx: int, dy: int) -> None:
        destination = Point(self.player.pos.x + dx, self.player.pos.y + dy)
        target = self.entity_at(destination)
        if target is not None:
            self.attack(self.player, target)
        elif self.game_map.is_walkable(destination):
            self.player.pos = destination

    def attack(self, attacker: Entity, defender: Entity) -> None:
        if attacker.fighter is None or defender.fighter is None:
            return
        damage = max(0, attacker.fighter.power - defender.fighter.armor)
        defender.fighter.hp -= damage
        self.log.append(f"{attacker.name} hits {defender.name} for {damage} damage")
        if defender.fighter.hp <= 0:
            self.log.append(f"{defender.name} dies")

def new_game(width: int = 40, height: int = 24, seed: int = 1, fill_threshold: float = 0.45) -> Game:
    game_map = generate_cellular_automata(width, height, seed, fill_threshold)
    repair_connectivity(game_map, seed)

    floor_tiles = []
    for y in range(game_map.height):
        for x in range(game_map.width):
            if game_map.tiles[y][x] == FLOOR:
                floor_tiles.append(Point(x, y))

    if not floor_tiles:
        raise RuntimeError("No floor tiles generated")

    player = Entity("player", floor_tiles[0], Fighter(hp=30, power=8, armor=2))

    rng = Random(seed + 2000)
    monsters = []
    available_tiles = floor_tiles[1:min(11, len(floor_tiles))]
    rng.shuffle(available_tiles)

    for i, pos in enumerate(available_tiles[:5]):
        monster_type = ["goblin", "orc", "skeleton", "troll", "zombie"][i % 5]
        monsters.append(Entity(monster_type, pos, Fighter(hp=10 + i * 2, power=4 + i, armor=i)))

    return Game(game_map, player, monsters, [])

def run_headless(seed: int, turns: int) -> Game:
    game = new_game(seed=seed)
    rng = Random(seed + 3000)
    moves = [Point(1, 0), Point(0, 1), Point(-1, 0), Point(0, -1)]
    for _ in range(turns):
        move = rng.choice(moves)
        game.move_player(move.x, move.y)
    return game

if __name__ == "__main__":
    run_headless(seed=7029, turns=200)
