        Point(point.x, point.y + 1),
        Point(point.x - 1, point.y),
        Point(point.x, point.y - 1),
    ]


def shortest_path(start: Point, goal: Point, walkable: set[Point]) -> list[Point] | None:
    if start not in walkable or goal not in walkable:
        return None
    queue: deque[Point] = deque([start])
    came_from: dict[Point, Point] = {}
    visited = {start}
    while queue:
        current = queue.popleft()
        if current == goal:
            path = [current]
            while current != start:
                current = came_from[current]
                path.append(current)
            path.reverse()
            return path[1:]
        for neighbor in cardinal_neighbors(current):
            if neighbor in visited or neighbor not in walkable:
                continue
            visited.add(neighbor)
            came_from[neighbor] = current
            queue.append(neighbor)
    return None


def distance(a: Point, b: Point) -> int:
    return abs(a.x - b.x) + abs(a.y - b.y)


def choose_flee_step(monster: Monster, player: Point, walkable: set[Point]) -> Point | None:
    options = [p for p in cardinal_neighbors(monster.position) if p in walkable]
    if not options:
        return None
    options.sort(key=lambda p: (-distance(p, player), p.y, p.x))
    return options[0]


def choose_wander_step(monster: Monster, walkable: set[Point], rng: Random) -> Point | None:
    options = [p for p in cardinal_neighbors(monster.position) if p in walkable]
    if not options:
        return None
    return rng.choice(options)


def choose_action(
    monster: Monster,
    player: Point,
    walkable: set[Point],
    visible: set[Point],
    rng: Random,
) -> Action:
    if monster.hp * 3 <= monster.max_hp:
        flee_step = choose_flee_step(monster, player, walkable)
        return Action("move", flee_step) if flee_step is not None else Action("wait")
    if player in visible:
        path = shortest_path(monster.position, player, walkable)
        if path:
            return Action("move", path[0])
        return Action("wait")
    wander_step = choose_wander_step(monster, walkable, rng)
    return Action("move", wander_step) if wander_step is not None else Action("wait")


def test_low_health_flees_away_from_player() -> None:
    walkable = {Point(x, 0) for x in range(5)}
    action = choose_action(Monster(Point(2, 0), 3, 9), Point(1, 0), walkable, set(), Random(1))
    assert action == Action("move", Point(3, 0))


def test_visible_player_is_chased_by_shortest_path() -> None:
    walkable = {Point(x, 0) for x in range(4)}
    action = choose_action(Monster(Point(0, 0), 5, 9), Point(3, 0), walkable, {Point(3, 0)}, Random(1))
    assert action == Action("move", Point(1, 0))
