from __future__ import annotations

from dataclasses import dataclass
from heapq import heappop, heappush


@dataclass(frozen=True, order=True, slots=True)
class Point:
    x: int
    y: int


def neighbors(point: Point) -> list[Point]:
    return [
        Point(point.x + 1, point.y),
        Point(point.x, point.y + 1),
        Point(point.x - 1, point.y),
        Point(point.x, point.y - 1),
    ]


def heuristic(a: Point, b: Point) -> int:
    return abs(a.x - b.x) + abs(a.y - b.y)


def reconstruct(came_from: dict[Point, Point], start: Point, goal: Point) -> list[Point]:
    current = goal
    path = [current]
    while current != start:
        current = came_from[current]
        path.append(current)
    path.reverse()
    return path[1:]


def find_path(
    start: Point,
    goal: Point,
    walk_costs: dict[Point, int],
    blocked: set[Point],
) -> list[Point] | None:
    if start in blocked or goal in blocked:
        return None
    if start not in walk_costs or goal not in walk_costs:
        return None
    frontier: list[tuple[int, int, Point]] = []
    heappush(frontier, (heuristic(start, goal), 0, start))
    came_from: dict[Point, Point] = {}
    cost_so_far: dict[Point, int] = {start: 0}
    sequence = 0
    while frontier:
        _, queued_cost, current = heappop(frontier)
        if queued_cost != cost_so_far[current]:
            continue
        if current == goal:
            return reconstruct(came_from, start, goal)
        for neighbor in neighbors(current):
            if neighbor in blocked or neighbor not in walk_costs:
                continue
            new_cost = cost_so_far[current] + walk_costs[neighbor]
            if neighbor in cost_so_far and new_cost >= cost_so_far[neighbor]:
                continue
            cost_so_far[neighbor] = new_cost
            came_from[neighbor] = current
            sequence += 1
            priority = new_cost + heuristic(neighbor, goal)
            heappush(frontier, (priority, new_cost, neighbor))
    return None


def total_cost(path: list[Point], walk_costs: dict[Point, int]) -> int:
    return sum(walk_costs[p] for p in path)


def test_cheaper_longer_route_beats_expensive_direct_route() -> None:
    points = {Point(x, y) for x in range(4) for y in range(2)}
    costs = {point: 1 for point in points}
    costs[Point(1, 0)] = 20
    path = find_path(Point(0, 0), Point(3, 0), costs, set())
    assert path is not None
    assert total_cost(path, costs) == 5
    assert Point(1, 0) not in path


def test_blocked_goal_returns_none() -> None:
    costs = {Point(0, 0): 1, Point(1, 0): 1}
    assert find_path(Point(0, 0), Point(1, 0), costs, {Point(1, 0)}) is None
