from __future__ import annotations

import json
from dataclasses import dataclass, field


@dataclass(slots=True)
class Entity:
    entity_id: int
    name: str
    inventory_ids: list[int] = field(default_factory=list)


@dataclass(slots=True)
class GameState:
    entities: dict[int, Entity]


def save_game(state: GameState) -> str:
    payload = {
        "entities": [
            {"id": entity.entity_id, "name": entity.name, "inventory": entity.inventory_ids}
            for entity in state.entities.values()
        ]
    }
    return json.dumps(payload, sort_keys=True)


def load_game(raw: str) -> GameState:
    payload = json.loads(raw)
    entities: dict[int, Entity] = {}
    for item in payload["entities"]:
        entity_id = int(item["id"])
        if entity_id in entities:
            raise ValueError(f"duplicate entity id: {entity_id}")
        inventory_ids = [int(value) for value in item.get("inventory", [])]
        entities[entity_id] = Entity(entity_id, str(item["name"]), inventory_ids)
    for entity in entities.values():
        for inventory_id in entity.inventory_ids:
            if inventory_id not in entities:
                raise ValueError(f"missing inventory entity id: {inventory_id}")
    return GameState(entities)


def test_round_trip_preserves_ids_and_inventory_references() -> None:
    potion = Entity(7, "potion")
    renamed_potion = Entity(8, "potion")
    hero = Entity(1, "hero", [7])
    state = GameState({1: hero, 7: potion, 8: renamed_potion})
    loaded = load_game(save_game(state))
    assert sorted(loaded.entities) == [1, 7, 8]
    assert loaded.entities[1].inventory_ids == [7]
    assert loaded.entities[7].name == "potion"


def test_duplicate_ids_are_rejected() -> None:
    raw = '{"entities": [{"id": 1, "name": "a"}, {"id": 1, "name": "b"}]}'
    try:
        load_game(raw)
    except ValueError as exc:
        assert "duplicate entity id" in str(exc)
    else:
        raise AssertionError("duplicate IDs should fail")


def test_empty_inventory_remains_empty() -> None:
    loaded = load_game(save_game(GameState({2: Entity(2, "goblin")})))
    assert loaded.entities[2].inventory_ids == []
