from __future__ import annotations

from dataclasses import dataclass, field
from typing import Protocol


@dataclass(frozen=True, slots=True)
class Point:
    x: int
    y: int


@dataclass(slots=True)
class Fighter:
    hp: int
    power: int
    armor: int


@dataclass(slots=True)
class Entity:
    entity_id: int
    name: str
    position: Point
    fighter: Fighter | None = None


@dataclass(frozen=True, slots=True)
class Event:
    actor_id: int
    message: str


@dataclass(slots=True)
class EventLog:
    events: list[Event] = field(default_factory=list)

    def append(self, event: Event) -> None:
        self.events.append(event)


class Command(Protocol):
    def execute(self, world: GameWorld) -> list[Event]: ...


@dataclass(slots=True)
class GameWorld:
    entities: dict[int, Entity]
    walkable: set[Point]
    log: EventLog = field(default_factory=EventLog)

    def apply(self, command: Command) -> list[Event]:
        events = command.execute(self)
        for event in events:
            self.log.append(event)
        return events


@dataclass(frozen=True, slots=True)
class MoveCommand:
    actor_id: int
    destination: Point

    def execute(self, world: GameWorld) -> list[Event]:
        actor = world.entities[self.actor_id]
        if self.destination not in world.walkable:
            return [Event(self.actor_id, f"{actor.name} bumps into an obstacle.")]
        actor.position = self.destination
        return [Event(self.actor_id, f"{actor.name} moves.")]


@dataclass(frozen=True, slots=True)
class AttackCommand:
    actor_id: int
    target_id: int

    def execute(self, world: GameWorld) -> list[Event]:
        actor = world.entities[self.actor_id]
        target = world.entities[self.target_id]
        if actor.fighter is None or target.fighter is None:
            return [Event(self.actor_id, "The attack has no effect.")]
        damage = max(0, actor.fighter.power - target.fighter.armor)
        target.fighter.hp -= damage
        return [Event(self.actor_id, f"{actor.name} hits {target.name} for {damage} damage.")]


def test_invalid_move_does_not_change_position() -> None:
    hero = Entity(1, "hero", Point(0, 0))
    world = GameWorld({1: hero}, {Point(0, 0)})
    events = world.apply(MoveCommand(1, Point(1, 0)))
    assert hero.position == Point(0, 0)
    assert events == [Event(1, "hero bumps into an obstacle.")]


def test_attack_clamps_damage_and_records_event() -> None:
    hero = Entity(1, "hero", Point(0, 0), Fighter(10, 2, 0))
    turtle = Entity(2, "turtle", Point(1, 0), Fighter(10, 1, 5))
    world = GameWorld({1: hero, 2: turtle}, {Point(0, 0), Point(1, 0)})
    events = world.apply(AttackCommand(1, 2))
    assert turtle.fighter is not None
    assert turtle.fighter.hp == 10
    assert events[0].message.endswith("0 damage.")
    assert world.log.events == events
